      "content": "const express = require('express');
const router = express.Router();
const { getTasksByStatus, updateTaskStatus } = require('./service');

router.get('/:projectId/tasks', async (req, res) => {
  const tasks = await getTasksByStatus(req.params.projectId, req.query.status);
  if (!tasks) return sendError(res, 404, 'NOT_FOUND', 'Tasks not found');
  res.json({ tasks });
});

router.patch('/:projectId/tasks/:taskId', async (req, res) => {
  const status = req.body.status;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid task status');
  const updatedTask = await updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!updatedTask) return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  res.json({ task: updatedTask });
});

exports.router = router;
